using System; using System.Text.RegularExpressions; using System.Linq; class Program { static void Main() { string text = "Sample Quiz Upload File\nQuestion 1: What is the capital of Vietnam?\nA. Ho Chi Minh City\nB. Da Nang\nC. Hanoi\nD. Hue\nAnswer: C\n\nQuestion 2: HTML stands for what?\nA. Hyper Text Markup Language\nB. Hot Mail\nC. How to Make Lasagna\nD. Home Tool Markup Language\nAnswer: A"; string t = Regex.Replace(text, @"\s+([A-D][\.\:\)\-])", "\n$1"); var s = new Regex(@"(?im)(?=(?:^|\n)\s*(?:c‚u\s*\d+|question\s*\d+|q\s*\d+|#\s*\d+|\d+\)|\d+\.))"); var blocks = s.Split(t).Where(b => !string.IsNullOrWhiteSpace(b)).ToList(); foreach(var b in blocks) { Console.WriteLine("BLOCK:"); Console.WriteLine(b.Trim()); var matches = Regex.Matches(b.Trim(), @"(?im)^\s*([A-D])\s*[\.\:\)\-]\s*(.+)$", RegexOptions.Multiline); Console.WriteLine($"Matches: {matches.Count}"); } } }
